"""Operator console for the Balkan.works Core platform."""


def render_admin_page() -> str:
    return '''<!doctype html><html lang="sr"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Administracija · Balkan.works</title><style>
:root{--ink:#092c26;--pine:#0d4036;--paper:#f7f8f4;--orange:#ff6c37;--line:#d9e3dc;--muted:#62746e;--red:#b54537;--mint:#e5f5eb}*{box-sizing:border-box}body{margin:0;background:var(--paper);font-family:Inter,system-ui,sans-serif;color:var(--ink)}.shell{display:grid;grid-template-columns:245px 1fr;min-height:100vh}.side{background:var(--pine);color:#fff;padding:25px 18px}.brand{color:#fff;text-decoration:none;font-size:23px;font-weight:900}.brand i{color:var(--orange)}.side p{color:#bed1ca;font-size:13px;line-height:1.5;margin:10px 0 28px}.menu{display:grid;gap:7px}.menu button{color:#eaf4ef;background:transparent;border:0;border-radius:8px;padding:12px;text-align:left;font:inherit;font-weight:700;cursor:pointer}.menu button:hover,.menu button.active{background:#ffffff18}.user{position:fixed;bottom:18px;color:#d5e4dd;font-size:12px}.main{padding:35px 40px;max-width:1450px;width:100%}.eyebrow{font-size:12px;text-transform:uppercase;letter-spacing:1.4px;color:var(--orange);font-weight:800}h1{font:46px Georgia,serif;letter-spacing:-1.5px;margin:7px 0 8px}.lead{color:var(--muted);margin:0 0 26px}.metrics{display:grid;grid-template-columns:repeat(4,1fr);gap:14px;margin:20px 0 28px}.metric{background:#fff;border:1px solid var(--line);border-radius:14px;padding:18px}.metric b{font-size:30px;display:block}.metric span{font-size:13px;color:var(--muted)}.card{background:#fff;border:1px solid var(--line);border-radius:14px;padding:20px;margin-bottom:20px}.card h2{font:25px Georgia,serif;margin:0 0 3px}.card p{color:var(--muted);font-size:13px;margin:5px 0 16px}.toolbar{display:flex;align-items:center;justify-content:space-between;gap:12px}.refresh,.action{border:0;border-radius:8px;padding:9px 12px;font-weight:800;cursor:pointer}.refresh{background:var(--pine);color:#fff}.action{background:#fff0ea;color:#a2381c}.action.verify{background:var(--mint);color:#18704f}table{border-collapse:collapse;width:100%;font-size:13px}th,td{padding:12px 8px;border-top:1px solid var(--line);text-align:left;vertical-align:middle}th{color:var(--muted);font-size:11px;text-transform:uppercase;letter-spacing:.7px}.tag{border-radius:20px;padding:5px 8px;background:#edf2ef;font-size:11px;font-weight:800}.tag.pending{background:#fff0da;color:#946100}.tag.verified,.tag.active{background:var(--mint);color:#18704f}.tag.blocked,.tag.inactive{background:#fff0ea;color:var(--red)}.hidden{display:none}.notice{margin:10px 0;padding:12px;border-radius:8px;background:#fff0ea;color:#963d2a;font-size:14px}.login{max-width:470px;margin:10vh auto;background:#fff;border:1px solid var(--line);border-radius:18px;padding:30px}.login input{width:100%;padding:12px;border:1px solid var(--line);border-radius:8px;margin:8px 0;font:inherit}.login button{background:var(--orange);color:#fff;border:0;border-radius:8px;padding:12px 14px;font-weight:800;cursor:pointer;margin-top:8px}@media(max-width:860px){.shell{display:block}.side{min-height:auto}.user{position:static;margin-top:20px}.main{padding:26px 18px}.metrics{grid-template-columns:1fr 1fr}.table-wrap{overflow:auto}}@media(max-width:480px){.metrics{grid-template-columns:1fr}h1{font-size:38px}}
</style></head><body><section id="login-view" class="login"><div class="eyebrow">Zaštićen pristup</div><h1>Administracija</h1><p>Prijavi se Balkan.works nalogom koji ima ulogu ADMIN ili MODERATOR.</p><input id="email" type="email" placeholder="Email"><input id="password" type="password" placeholder="Lozinka"><button id="login">Prijavi se →</button><div id="login-notice"></div></section><section id="app-view" class="shell hidden"><aside class="side"><a class="brand" href="/">balkan<i>.</i>works</a><p>Operativni centar za korisnike, firme, sadržaj i moderaciju.</p><nav class="menu"><button class="active" data-tab="overview">Pregled platforme</button><button data-tab="users">Korisnici</button><button data-tab="businesses">Firme i verifikacije</button><button data-tab="listings">Oglasi i sadržaj</button><button data-tab="audit">Audit trag</button></nav><div class="user" id="admin-email"></div></aside><main class="main"><div class="eyebrow">Core platform control</div><h1 id="heading">Pregled platforme</h1><p class="lead" id="subheading">Stanje celog Balkan.works ekosistema na jednom mestu.</p><div id="notice" class="notice hidden"></div><section id="overview" class="tab"><div class="metrics"><div class="metric"><b id="metric-users">—</b><span>korisnika</span></div><div class="metric"><b id="metric-businesses">—</b><span>firmi</span></div><div class="metric"><b id="metric-offers">—</b><span>ponuda</span></div><div class="metric"><b id="metric-queue">—</b><span>čeka verifikaciju</span></div></div><div class="card"><div class="toolbar"><div><h2>Operativni tok</h2><p>Moderacija je auditable: svaka blokada, verifikacija i skrivanje oglasa ostaju zabeleženi.</p></div><button class="refresh" onclick="refreshAll()">Osveži podatke</button></div></div></section><section id="users" class="tab hidden"><div class="card"><h2>Korisnici</h2><p>Možeš blokirati nalog koji krši pravila. Ne možeš blokirati sopstveni nalog.</p><div class="table-wrap"><table><thead><tr><th>Email</th><th>Uloga</th><th>Status</th><th>Pridružen</th><th>Akcija</th></tr></thead><tbody id="users-body"></tbody></table></div></div></section><section id="businesses" class="tab hidden"><div class="card"><h2>Firme i verifikacije</h2><p>Verifikuj firmu nakon provere podataka. Status je vidljiv kroz ceo ekosistem.</p><div class="table-wrap"><table><thead><tr><th>Firma</th><th>Lokacija</th><th>Status</th><th>Pridružena</th><th>Akcija</th></tr></thead><tbody id="businesses-body"></tbody></table></div></div></section><section id="listings" class="tab hidden"><div class="card"><h2>Oglasi i sadržaj</h2><p>Neusklađen ili prijavljen oglas možeš sakriti; zapis ostaje u auditu.</p><div class="table-wrap"><table><thead><tr><th>Oglas</th><th>Tip</th><th>Lokacija</th><th>Status</th><th>Akcija</th></tr></thead><tbody id="listings-body"></tbody></table></div></div></section><section id="audit" class="tab hidden"><div class="card"><h2>Audit trag</h2><p>Poslednjih 100 operativnih događaja na Core platformi.</p><div class="table-wrap"><table><thead><tr><th>Vreme</th><th>Događaj</th><th>Resurs</th><th>Akter</th></tr></thead><tbody id="audit-body"></tbody></table></div></div></section></main></section><script>
const token=()=>localStorage.getItem('balkan_access_token');const h=()=>({authorization:'Bearer '+token()});const esc=s=>String(s??'').replace(/[&<>"']/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]));const stamp=s=>s?new Date(s).toLocaleString('sr-RS'):'—';const notice=(message)=>{let n=document.querySelector('#notice');n.textContent=message;n.classList.remove('hidden')};async function call(path,options={}){const r=await fetch(path,{...options,headers:{...h(),...(options.headers||{})}});const d=await r.json().catch(()=>({}));if(!r.ok)throw new Error(d.detail||'Zahtev nije uspeo.');return d}function tag(value){const raw=String(value||'').toLowerCase(),cls=raw==='verified'||raw==='true'?'verified':raw==='pending'?'pending':raw==='false'||raw==='inactive'?'inactive':'';return '<span class="tag '+cls+'">'+esc(value)+'</span>'}async function refreshAll(){try{document.querySelector('#notice').classList.add('hidden');const [d,u,b,l,a,me]=await Promise.all([call('/api/admin/dashboard'),call('/api/admin/users'),call('/api/admin/businesses'),call('/api/admin/listings'),call('/api/admin/audit-logs'),call('/api/me')]);document.querySelector('#metric-users').textContent=d.users;document.querySelector('#metric-businesses').textContent=d.businesses;document.querySelector('#metric-offers').textContent=d.offers;document.querySelector('#metric-queue').textContent=d.moderation_queue;document.querySelector('#admin-email').textContent=me.user.email+' · '+me.user.role;document.querySelector('#users-body').innerHTML=u.map(x=>'<tr><td>'+esc(x.email)+'</td><td>'+tag(x.role)+'</td><td>'+tag(x.is_active?'active':'blocked')+'</td><td>'+stamp(x.created_at)+'</td><td>'+(x.is_active?'<button class="action" onclick="blockUser(\''+x.id+'\')">Blokiraj</button>':'—')+'</td></tr>').join('')||'<tr><td colspan="5">Nema korisnika.</td></tr>';document.querySelector('#businesses-body').innerHTML=b.map(x=>'<tr><td><b>'+esc(x.name)+'</b></td><td>'+esc(x.city_name)+', '+esc(x.country_code)+'</td><td>'+tag(x.verification_status)+'</td><td>'+stamp(x.created_at)+'</td><td>'+(x.verification_status==='PENDING'?'<button class="action verify" onclick="verifyBusiness(\''+x.id+'\')">Verifikuj</button>':'—')+'</td></tr>').join('')||'<tr><td colspan="5">Nema firmi.</td></tr>';document.querySelector('#listings-body').innerHTML=l.map(x=>'<tr><td><b>'+esc(x.title)+'</b></td><td>'+tag(x.listing_type)+'</td><td>'+esc(x.city_name||'—')+', '+esc(x.country_code)+'</td><td>'+tag(x.is_active?'active':'inactive')+'</td><td>'+(x.is_active?'<button class="action" onclick="hideListing(\''+x.id+'\')">Sakrij</button>':'—')+'</td></tr>').join('')||'<tr><td colspan="5">Nema oglasa.</td></tr>';document.querySelector('#audit-body').innerHTML=a.map(x=>'<tr><td>'+stamp(x.created_at)+'</td><td>'+esc(x.action)+'</td><td>'+esc(x.resource_type)+(x.resource_id?' · '+esc(x.resource_id.slice(0,8)):'')+'</td><td>'+esc(x.actor_user_id?x.actor_user_id.slice(0,8):'sistem')+'</td></tr>').join('')||'<tr><td colspan="4">Nema operativnih zapisa.</td></tr>'}catch(e){notice(e.message);if(/401|403|Nema dozvolu/i.test(e.message)){localStorage.removeItem('balkan_access_token');document.querySelector('#app-view').classList.add('hidden');document.querySelector('#login-view').classList.remove('hidden')}}}async function blockUser(id){if(confirm('Blokirati ovaj korisnički nalog?')){try{await call('/api/admin/users/'+id+'/block',{method:'POST'});refreshAll()}catch(e){notice(e.message)}}}async function verifyBusiness(id){try{await call('/api/admin/businesses/'+id+'/verify',{method:'POST'});refreshAll()}catch(e){notice(e.message)}}async function hideListing(id){if(confirm('Sakriti ovaj oglas?')){try{await call('/api/admin/listings/'+id+'/hide',{method:'POST'});refreshAll()}catch(e){notice(e.message)}}}document.querySelectorAll('[data-tab]').forEach(button=>button.onclick=()=>{document.querySelectorAll('[data-tab]').forEach(x=>x.classList.remove('active'));button.classList.add('active');document.querySelectorAll('.tab').forEach(x=>x.classList.add('hidden'));document.querySelector('#'+button.dataset.tab).classList.remove('hidden');const titles={overview:['Pregled platforme','Stanje celog Balkan.works ekosistema na jednom mestu.'],users:['Korisnici','Nalozi, uloge i bezbednost platforme.'],businesses:['Firme i verifikacije','Poverenje firme počinje proverom.'],listings:['Oglasi i sadržaj','Moderacija marketplace sadržaja.'],audit:['Audit trag','Trajan zapis operativnih odluka.']};document.querySelector('#heading').textContent=titles[button.dataset.tab][0];document.querySelector('#subheading').textContent=titles[button.dataset.tab][1]});document.querySelector('#login').onclick=async()=>{try{const r=await fetch('/api/login',{method:'POST',headers:{'content-type':'application/json'},body:JSON.stringify({email:document.querySelector('#email').value,password:document.querySelector('#password').value})});const d=await r.json();if(!r.ok)throw new Error(d.detail||'Prijava nije uspela.');localStorage.setItem('balkan_access_token',d.access_token);boot()}catch(e){document.querySelector('#login-notice').textContent=e.message}};function boot(){if(!token())return;document.querySelector('#login-view').classList.add('hidden');document.querySelector('#app-view').classList.remove('hidden');refreshAll()}boot();
</script></body></html>'''
